/******************************************************************************
 *
 * NBHAS Controller Builder
 *
 * Combines all controller modules into one Shopify asset.
 *
 ******************************************************************************/

const fs = require('fs');
const path = require('path');

const controllerDir = path.join(__dirname, '..', 'controller');
const outputFile = path.join(
    __dirname,
    '..',
    'assets',
    'nbhas-assessment.js'
);

const header = `/******************************************************************************
 *
 * AUTO GENERATED FILE
 *
 * DO NOT EDIT THIS FILE
 *
 * Source:
 *   controller/
 *
 * Generated:
 *   ${new Date().toISOString()}
 *
 ******************************************************************************/

`;

const files = fs.readdirSync(controllerDir)
    .filter(file => file.endsWith('.js'))
    .sort();

let output = header;

files.forEach(file => {

    console.log('Adding', file);

    const contents = fs.readFileSync(
        path.join(controllerDir, file),
        'utf8'
    );

    output += '\n';
    output += '/******************************************************************************/\n';
    output += `/* ${file} */\n`;
    output += '/******************************************************************************/\n\n';
    output += contents;
    output += '\n';

});

fs.writeFileSync(
    outputFile,
    output,
    'utf8'
);

console.log('');
console.log('========================================');
console.log('NBHAS Controller Build Complete');
console.log('========================================');
console.log(outputFile);
